// --- FILTRE DE CONSOLE POUR MASQUER LES ERREURS DE WEBSOCKET DE VITE DANS LE PRÉVISU ---
if (typeof window !== "undefined") {
  const originalError = console.error;
  console.error = function (...args) {
    const msg = args.join(" ");
    if (
      msg.includes("WebSocket") ||
      msg.includes("vite") ||
      msg.includes("hmr") ||
      msg.includes("hot-update") ||
      msg.includes("failed to connect") ||
      msg.includes("entity too large")
    ) {
      return; // Ignore de façon silencieuse les bruits de WebSocket HMR
    }
    originalError.apply(console, args);
  };

  const originalWarn = console.warn;
  console.warn = function (...args) {
    const msg = args.join(" ");
    if (
      msg.includes("WebSocket") ||
      msg.includes("vite") ||
      msg.includes("hmr") ||
      msg.includes("hot-update") ||
      msg.includes("failed to connect")
    ) {
      return; // Ignore de façon silencieuse
    }
    originalWarn.apply(console, args);
  };

  window.addEventListener("error", (event) => {
    if (
      event.message &&
      (event.message.includes("WebSocket") ||
        event.message.includes("vite") ||
        event.message.includes("hmr") ||
        event.message.includes("WS"))
    ) {
      event.preventDefault();
    }
  });

  window.addEventListener("unhandledrejection", (event) => {
    const reasonStr = String(event.reason || "");
    if (
      reasonStr.includes("WebSocket") ||
      reasonStr.includes("vite") ||
      reasonStr.includes("hmr") ||
      reasonStr.includes("WS")
    ) {
      event.preventDefault();
    }
  });
}

