  const reconcileExpenses = async (prev: any[], next: any[]) => {
    const userId = auth.currentUser?.uid;
    if (!userId) return;
    const deleted = prev.filter(p => !next.some(n => n.id === p.id));
    for (const item of deleted) {
      if (item.id && typeof item.id === 'string' && item.id.length > 5 && isNaN(Number(item.id))) {
        await dataService.deleteExpense(item.id);
      }
    }
    const addedOrModified = next.filter(n => {
      const p = prev.find(x => x.id === n.id);
      if (!p) return true;
      return p.total !== n.total || p.fecha !== n.fecha || p.fournisseur !== n.fournisseur || p.cat !== n.cat || p.status !== n.status || p.lien !== n.lien;
    });
    for (const item of addedOrModified) {
      try {
        const saved = await dataService.saveExpense(userId, item);
        if (saved.id && saved.id !== item.id) {
          _setDepenses(current => current.map(c => c.id === item.id ? { ...c, id: saved.id } : c));
        }
      } catch (err) {
        console.error("Failed to save expense:", err);
      }
    }
  };
  const setDepenses = (value: any[] | ((prev: any[]) => any[])) => {
    _setDepenses((prev) => {
      const next = typeof value === "function" ? value(prev) : value;
      reconcileExpenses(prev, next);
      return next;
    });
  };
